INSERT INTO `hotels` VALUES (1,'Grand Rocky Hotel','grand-rocky-hotel','Berlokasi di Bukittinggi, 6 menit jalan kaki dari Jam Gadang, Grand Rocky Hotel Bukittinggi menyediakan kamar ber-AC dan taman. Fasilitas yang tersedia di akomodasi ini adalah restoran, layanan kamar, resepsionis 24 jam, dan WiFi gratis di seluruh area akomodasi. Akomodasi ini menawarkan mesin ATM dan layanan concierge untuk Anda.  Semua unit di hotel dilengkapi area tempat duduk, TV layar datar dengan saluran kabel, dan brankas. Unit memiliki meja kerja.  Istana Bung Hatta berjarak kurang dari 1 km dari Grand Rocky Hotel Bukittinggi, sementara Stasiun Kereta Padang Panjang terletak sejauh 20 km. Bandara terdekat adalah Bandara Internasional Minangkabau, 71 km dari Grand Rocky Hotel Bukittinggi.','Grand Rocky Hotel, Bukittinggi','[\"hotel-images/01KKBM599QSFKMB9PYP7CN6C2Y.jpg\", \"hotel-images/01KKBM6HZRQY6SS0E1XMFWNDWF.jpg\"]',4,1000000,'0752627000',5000000,'2026-03-10 07:37:20','2026-03-24 13:33:23',-0.30284460,100.36642110),(3,'Monopoli Hotel','monopoli-hotel','Monopoli Hotel Bukittinggi adalah hotel bintang 4 yang berlokasi di Guguk Panjang, Bukittinggi yang menawarkan berbagai tipe kamar sesuai kebutuhan kamu.','M9V9+J5 Bukit Cangang Kayu Ramang, Bukittinggi City, West Sumatra','[\"hotel-images/01KMFYPRSZ529TSM2B4W8M6WKN.jpeg\"]',4,750000,'082385293324',4500000,'2026-03-24 12:56:53','2026-03-24 13:56:59',-0.30907000,100.37055000);
/*!40000 ALTER TABLE `hotels` ENABLE KEYS */;
