INSERT INTO `wisatas` VALUES (2,3,'Panorama Baru','panorama-baru','Panorama Baru Bukittinggi (atau Taman Wisata Panorama Baru) adalah destinasi wisata alam yang menawarkan pemandangan tebing Ngarai Sianok yang memanjang, pepohonan hijau rindang, serta latar belakang Gunung Singgalang dan Gunung Marapi. Terletak sekitar 5 kilometer dari pusat Kota Bukittinggi (area Jam Gadang), tempat ini menjadi alternatif yang lebih tenang dan asri dibandingkan area Panorama Lubang Jepang yang lebih populer di pusat kota.',5000.00,'Taman Panorama Baru, Bukittinggi','wisata-images/01KMFWZYVP87ZRFS3FWDQNQFT0.jpeg','2026-03-24 12:26:57','2026-03-24 12:27:35',-0.30907000,100.37055000,1,1,0),(3,2,'Jam Gadang','jam-gadang','Jam Gadang adalah menara jam ikonik setinggi 26 meter yang menjadi simbol utama Kota Bukittinggi, Sumatera Barat. Nama \"Jam Gadang\" berasal dari bahasa Minangkabau yang berarti \"jam besar\" karena memiliki empat jam berdiameter 80 cm di setiap sisinya. ',NULL,'Jam Gadang, Bukittinggi','wisata-images/01KMFXFXJZET77H793ASC7H20W.jpeg','2026-03-24 12:35:40','2026-03-24 12:35:40',-0.30907000,100.37055000,1,1,1);
